UPDATE users
SET storage_used_bytes = #{bytes,jdbcType=BIGINT}
WHERE user_id = #{userId,jdbcType=BIGINT}

UPDATE users
SET storage_used_bytes = GREATEST(0, storage_used_bytes + #{delta,jdbcType=BIGINT})
WHERE user_id = #{userId,jdbcType=BIGINT}

UPDATE users
SET storage_limit_mb = #{limitMb,jdbcType=INTEGER}
WHERE user_id = #{userId,jdbcType=BIGINT}
